var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"쓰러트렸나......?","JPN":"倒したか……？","ENG":"Is it dead?","TWN":"打倒了嗎？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"쿨럭! 쿨럭!!","JPN":"ゲホ！　ゲホッ！！","ENG":"*Cough!* *Cough!*","TWN":"咳咳！咳咳！！"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"사령관님, 괜찮으십니까?!","JPN":"司令官、大丈夫ですか！？","ENG":"Commander, are you okay?!","TWN":"司令官大人，您沒事吧？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"괜찮아. 오랜만에 무리했더니 조금 피곤할 뿐이야.","JPN":"大丈夫、久々に無理をしたせいで少し疲れただけだ。","ENG":"I am. I'm just a little bit exhausted from using my power so often.","TWN":"沒事。只是太久沒有這麼激烈活動，所以有些累了。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"뭘 그렇게 빤히 쳐다보고 그러나?","JPN":"なぜそんなに見ている？","ENG":"Why are you staring at me like that?","TWN":"你為什麼直勾勾地盯著我啊？"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"할머니에게 그런 자극적인 눈빛은 너무 부담스러운데 말이야.","JPN":"年寄りがそんな刺激的な眼差しを浴びたら体にこたえるぞ。","ENG":"I'm too old for such passionate attention.","TWN":"這種熱烈的視線對一個老奶奶來說，還挺有負擔的呢。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"아뇨, 아무것도 아닙니다. 죄송합니다.","JPN":"いや、なんでもありません。失礼いたしました。","ENG":"Ah, nothing. I'm sorry.","TWN":"不，沒什麼。非常抱歉。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"그보다 전 뉴 오하이오에 탑승해서 탈출 준비를 하겠습니다.","JPN":"私はニューオハイオに搭乗して脱出の準備をします。","ENG":"I'm going to go get the New Ohio ready to take us out of here.","TWN":"總之，我要準備搭乘新俄亥俄撤退了。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"차원 폭풍에서 빠져나가려면 제가 가진 항법 데이터가 필요하니까요.","JPN":"次元の暴風から抜け出すには私の航法データが必要ですからね。","ENG":"She'll need my navigation data to find her way out of this storm.","TWN":"畢竟要脫離次元風暴，會需要我手上的航行資料。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"그동안 사령관님은 특무함 내의 생존자들을 모아 주십시오.","JPN":"その間、司令官は特務艦の中の生存者を集めてください。","ENG":"In the meantime, Commander, I'd like you to collect the survivors in the auxiliary ship.","TWN":"這段時間就請司令官大人召集特務艦內的倖存者吧。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"알겠네, 부탁하지.","JPN":"わかった、頼むぞ。","ENG":"Sure, I'll do that.","TWN":"知道了，那就麻煩你了。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"COMPUTER_VOICE_NULL_RED","text":{"KOREA":"명령권자 탑승 확인.","JPN":"命令権者の搭乗を確認。","ENG":"Administrator is onboard. Verifying permissions...","TWN":"確認命令權所有者搭乘。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_SYS_START1"},{"id":"L20_1","type":"dialog","speaker":"COMPUTER_VOICE_NULL_RED","text":{"KOREA":"델타세븐 부사령관, 도미닉 킹 레지날드 준장.","JPN":"デルタセブンの副司令官、ドミニーク・キング・レジナルド准将。","ENG":"Dominic King Reginald, brigadier general and the deputy commander of Delta Seven.","TWN":"第七三角洲副司令官，多明尼克·金·雷吉納德准將。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L21_1","type":"dialog","speaker":"COMPUTER_VOICE_NULL_RED","text":{"KOREA":"뉴 오하이오의 모든 권한이 허가됩니다.","JPN":"ニューオハイオのすべての権限が付与されます。","ENG":"You have full control of the New Ohio.","TWN":"擁有新俄亥俄的所有權限許可。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L22_1","type":"dialog","speaker":"COMPUTER_VOICE_NULL_RED","text":{"KOREA":"현재 부상병들을 수용하기 위해 정보부 특무함과 랑데부 시퀀스를 진행 중입니다.","JPN":"現在、負傷兵を受け入れるために情報局の特務艦とランデブーシークエンスを実施しています。","ENG":"Currently, the rendezvous sequence is in process to receive the wounded personnel from the Intelligence Agency's auxiliary ship.","TWN":"目前，為接收負傷士兵，正進行與情報部特務艦的會合程序。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......진행을 취소한다.","JPN":"……実施を取り消す。","ENG":"Cancel that.","TWN":"……取消進行。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"이터니움 드라이브 최대출력, 긴급 다이브 시퀀스를 준비하도록.","JPN":"エタニウムドライブの最大出力で緊急ダイブのシークエンスを準備せよ。","ENG":"Maximize the Eternium drive output, and activate the rush Dive sequence.","TWN":"永恆之金引擎最大功率，準備緊急躍入程序。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"목표는 융해된 차원 계면의 틈, 허수공간이다.","JPN":"目標は融解された次元界面の狭間、虚数空間だ。","ENG":"We're entering a tear on the dimension surface, to imaginary space underneath.","TWN":"目標為融解的次元邊界裂縫，虛數空間。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"COMPUTER_VOICE_NULL_RED","text":{"KOREA":"명령 확인했습니다.","JPN":"命令を受け付けました。","ENG":"New command confirmed.","TWN":"確認命令。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L28_1","type":"dialog","speaker":"COMPUTER_VOICE_NULL_RED","text":{"KOREA":"랑데부 시퀀스 취소, 긴급 다이브 준비.","JPN":"ランデブーシークエンスをキャンセル、緊急ダイブの準備を開始。","ENG":"Canceling the rendezvous sequence and initializing a rush Dive...","TWN":"取消會合程序，準備緊急躍入。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_23"},{"id":"L30_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"도미닉?","JPN":"ドミニーク？","ENG":"Dominic?","TWN":"多明尼克。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L31_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"지금 뭐하는 건가! 뉴 오하이오가 멀어지고 있잖아?","JPN":"何をしている！　ニューオハイオから遠ざかってるではないか？","ENG":"What are you doing? The New Ohio is moving away!","TWN":"你在幹什麼！新俄亥俄離我們越來越遠了啊？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"죄송합니다, 사령관님.","JPN":"申し訳ありません、司令官。","ENG":"I'm sorry, Commander.","TWN":"非常抱歉，司令官大人。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"아까는 말씀드리지 않았지만, 이곳에서 로스트 쉽을 지키고 있던 4종 침식체는 그 녀석 하나가 아닙니다.","JPN":"先ほどは伏せていましたが、ここでロストシップを守っていた第4種侵食体は\\nあの一体だけではありません。","ENG":"I didn't tell you this, but the one we fought wasn't the only Category 4 C.O. guarding the Lost Ship.","TWN":"剛才沒有告訴您，這裡守護失落艦船的4類侵蝕體並非只有一隻。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"뭐? 뭐라고?","JPN":"なっ、何だと？","ENG":"Say what?","TWN":"你、你說什麼？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L35_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"이 거대한 차원 폭풍은 불멸체 코어를 지키던 다수의 4종 침식체들이 서로 공명하면서 만들어 낸 현상입니다.","JPN":"この巨大な次元の暴風は、不滅体コアを守っていた\\n複数の第4種侵食体どもが共鳴し合って発生させた現象です。","ENG":"This massive dimensional storm is the result of multiple Category 4 C.O.s around the Immortal System Core resonating with each other.","TWN":"這個巨大的次元風暴，是守護不滅者核心的許許多多4類侵蝕體，它們互相共鳴所產生的現象。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"불멸체 코어가 사라진 이상, 각지에 잠들어 있던 그 녀석들이 곧 이곳으로 도착할 겁니다.","JPN":"不滅体コアが消えた以上、各地に眠っていたやつらが\\nまもなくこちらに到着するでしょう。","ENG":"Now that the Core's gone, the other C.O.s that were sleeping in different places will be here soon.","TWN":"既然不滅者核心已經消失了，那麼沉眠於各地的4類侵蝕體很快就會到那裡去。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"4종 침식체가 다수, 그리고 여기로 모여들고 있다고?","JPN":"第4種侵食体が複数だと？\\nしかも、こっちに向かってきている？","ENG":"There are multiple Category 4 C.O.s, and they're coming here right now?","TWN":"你說有許多4類侵蝕體，而且它們會聚集到這裡來？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L38_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그럼 더 서둘러야지! 당장 여기로 와서 부상자들을 수용하게!","JPN":"なら急がねば！　ただちに負傷兵を搬送しないと！","ENG":"That's all the more reason we get the hell out of here! Come back and pick up the wounded now!","TWN":"那更要抓緊時間啊！你馬上到這裡來接收負傷者！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"아니요, 그런 식으로는 아무도 살아남을 수 없습니다.","JPN":"いいえ、それでは誰も生き残れません。","ENG":"No, you can't save anyone...","TWN":"不，那樣做誰都沒辨法活命的"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"그런 식으로...... 모든 걸 지키려고 해서는 말이죠.","JPN":"そうやって……全員を守ろうとするやり方じゃ。","ENG":"if you try to protect everything.","TWN":"如果這樣做……能保護所有人的話。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"자네, 무슨 말을 하고 있는 건가?","JPN":"ドミニーク、いったい何を言いだすんだ。","ENG":"What are you talking about?","TWN":"你，在說什麼？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L42_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"저는 지금부터 뉴 오하이오를 미끼로 삼아 4종 침식체들과 함께 허수공간으로 다이브 할 생각입니다.","JPN":"私はこれからニューオハイオをエサにし、第4種侵食体ともども\\n虚数空間へダイブするつもりです。","ENG":"From now on, I'm going to use the New Ohio to lure those Category 4 C.O.s and dive into imaginary space with them.","TWN":"現在開始，我準備把新俄亥俄當作誘餌，和4類侵蝕體一起躍入至虛數空間。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"그러면 이 차원폭풍도 사라지고 사령관님을 포함해서 모두들 안전하게 귀환할 수 있을 겁니다.","JPN":"そうすればこの次元の暴風も消滅し、\\n司令官含め全員が安全に帰還できるはずです。","ENG":"When they're gone, this dimensional storm will go too, and you and everyone else will be able to return safely.","TWN":"這樣一來，這個次元風暴就會消失，包括司令官在內的所有人都能安全地返回。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"무슨 바보 같은 소리야?! 허수 공간으로 빨려나가면 다시 돌아올 수 없어!","JPN":"なにバカなことを言っている！？\\n一度虚数空間に取り込まれたら、二度と帰れないんだぞ！","ENG":"Are you crazy? Once you're sucked into imaginary space, you can never come back out!","TWN":"你在說什麼傻話？！被吸進虛數空間後，你就再也回不來了！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L46_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그건...... 그건 제이나가 했던 것과 같은 짓이지 않나!","JPN":"それじゃあ……ジェイナと同じやり方じゃないか！","ENG":"And that's... That's exactly what Jaina did!","TWN":"這……這不是和婕娜做的事一樣嗎！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"사령관으로서 절대 허락할 수 없네!","JPN":"司令官として決して許可できない！","ENG":"As your commander, I can't let you do that!","TWN":"作為司令官，我絕對不允許你這麼做！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"COMPUTER_VOICE_NULL_RED","text":{"KOREA":"제 4종 침식체 다수, 급속 접근.","JPN":"複数の第4種侵食体が急速に接近中。","ENG":"Multiple Category 4 C.O.s approaching at high speed.","TWN":"大量4類侵蝕體急速接近。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L2_1","type":"dialog","speaker":"COMPUTER_VOICE_NULL_RED","text":{"KOREA":"근접 교전거리 돌파, 함 외부와 접촉합니다.","JPN":"近接交戦距離を突破、艦船の表面に接触します。","ENG":"Within close combat range... Now, they're in contact with the exterior of the ship.","TWN":"突破交戰距離，接觸到艦船外部。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L3_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"......죄송합니다. 사령관님.","JPN":"……申し訳ありません、司令官。","ENG":"... I'm sorry, Commander.","TWN":"……非常抱歉。司令官。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"하지만 지금은 이 방법뿐이군요.","JPN":"ですが、今はこの方法しかないのです。","ENG":"But this is the only solution I can think of.","TWN":"但是現在只有這個辦法了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"그럼...... 무운을 빕니다, 안녕히.","JPN":"それでは……ご武運を。失礼します。","ENG":"Now, good luck. And goodbye.","TWN":"那……祝您武運昌隆，再見了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"도미닉!!","JPN":"ドミニーク！！","ENG":"Dominic!","TWN":"多明尼克！！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_MECHANIC_COFFIN_START"}]`);export{e as default};